import { generateText, tool } from 'ai';
import { createStreamableUI } from 'ai/rsc';
import { openai } from '@ai-sdk/openai';

import { pineconeIndex } from './vector-stores/pinecone';

const searchTool = tool({
  description: 'Search company documents',
  parameters: z.object({ query: z.string() }),
  execute: async ({ query }) => {
    const results = await pineconeIndex.query({
      vector: embedding(query),
      topK: 5,
      includeMetadata: true
    });
    return {
      sources: results.matches.map((m, i) => `
[Source ${i+1}] ${m.metadata?.text || ''}
Score: ${m.score}`)
    };
  }
});

export async function agenticRAG(query: string) {
  const ui = createStreamableUI();

  ui.update(<div>Planning retrieval...</div>);

  const { text, toolResults } = await generateText({
    model: openai('gpt-4o'),
    prompt: `Answer using ONLY these sources:\n\n{{sources}}\n\nQuery: ${query}`,
    tools: { search: searchTool },
    toolChoice: 'auto',
    maxTokens: 2000
  });

  ui.update(<>
    <div>{text}</div>
    {toolResults?.map((result, i) => (
      <div key={i}>Sources: {result.content.sources.join('\n')}</div>
    ))}
  </>);

  return ui.value;
}

import { streamText, createStreamableValue } from 'ai';
import { z } from 'zod';

const planQueryTool = tool({
  description: 'Plan optimal retrieval queries',
  parameters: z.object({
    queries: z.array(z.string()),
    reasoning: z.string()
  }),
  execute: async ({ queries }) => {
    // Execute parallel searches
    const results = await Promise.all(
      queries.map(q => searchTool.execute({ query: q }))
    );
    return { combinedSources: results.flatMap(r => r.sources) };
  }
});

export async function* agentLoop(query: string) {
  const planningResult = await generateText({
    model: openai('gpt-4o'),
    tools: { planQuery: planQueryTool },
    prompt: `Plan 2-3 specific queries for: ${query}`
  });

  const stream = await streamText({
    model: openai('gpt-4o'),
    tools: { search: searchTool },
    messages: [
      { role: 'user', content: query },
      planningResult
    ]
  });

  for await (const chunk of stream.textStream) {
    yield chunk;
  }
}

import { Suspense } from 'react';
import { agenticRAG } from './agent-rag';

export default async function RAGPage({ params }: { params: { query: string } }) {
  return (
    <Suspense fallback={<div>Generating answer...</div>}> 
      <div className="prose max-w-2xl mx-auto p-8">
        {await agenticRAG(params.query)}
      </div>
    </Suspense>
  );
}

export const revalidate = 3600; // 1 hour

import { NextRequest } from 'next/server';

export const runtime = 'edge';

export async function POST(req: NextRequest) {
  const { query } = await req.json();

  const stream = await agentLoop(query);

  return new Response(stream, {
    headers: {
      'Content-Type': 'text/plain; charset=utf-8',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive',
    },
  });
}

