import { createVex } from '@vex_dev/sdk';
import { streamText } from 'ai';

const vex = createVex({
  projectId: process.env.VEX_PROJECT_ID!,
  apiKey: process.env.VEX_API_KEY!
});

export async function* verifiedAgentStream(query: string) {
  const rawStream = await streamText({
    model: openai('gpt-4o'),
    tools: { search: searchTool },
    messages: [{ role: 'user', content: query }]
  });

  // Vex verifies streaming chunks
  const verifiedStream = await vex.verify.stream({
    stream: rawStream.textStream,
    checks: [
      'source-faithfulness',
      'hallucination-detection',
      { hallucination: { threshold: 0.8 } },
      'citation-verification'
    ],
    context: {
      query,
      sources: toolResults?.sources || []
    }
  });

  for await (const chunk of verifiedStream) {
    if (chunk.verified) {
      yield chunk.content;
    } else {
      // Insert correction or citation
      yield `[VEX: ${chunk.issues?.[0]?.type}] `;
    }
  }
}

import { createVex } from '@vex_dev/sdk';

const vex = createVex({ /* config */ });

const validatedSearchTool = tool({
  ...searchTool,
  execute: async (params) => {
    const rawResults = await searchTool.execute(params);

    const validation = await vex.verify.tool({
      toolName: 'search',
      input: params,
      output: rawResults,
      checks: [
        'query-relevance',
        'result-completeness',
        { retrieval: { minScore: 0.7 } }
      ]
    });

    if (!validation.passed) {
      throw new Error(`Tool validation failed: ${validation.issues}`);
    }

    return rawResults;
  }
});

export async function verifiedPlanning(query: string) {
  const planningStream = await streamText({
    model: openai('gpt-4o'),
    tools: { planQuery: planQueryTool }
  });

  const planningResult = await vex.verify.plan({
    plannedQueries: planningStream.toolResults,
    originalQuery: query,
    checks: [
      'query-planning-accuracy',
      'cross-source-consistency',
      { intentAlignment: { threshold: 0.85 } }
    ]
  });

  if (!planningResult.passes) {
    // Fallback to single direct query
    return directRetrieval(query);
  }

  return planningStream;
}
